function.arguments:
{"code":"(* Physical constants in GeV units *)
alpha = 1/137.035999;
echarge = Sqrt[4 Pi alpha];   (* elementary charge in natural/Gaussian-HL units *)
Nc = 3;
Fpi = 0.09221;        (* GeV, pion decay constant *)
Mpi = 0.13957;        (* GeV, charged pion mass *)
Mrho = 0.7755;        (* GeV, rho(770) mass *)

(* Eq.(1): chiral anomaly low-energy theorem F_3pi *)
F3pi = echarge*Nc/(12 Pi^2 Fpi^3);
Print["Eq.(1)  F_3pi = ", F3pi, " GeV^-3"];

(* Eq.(2): pi0 -> gamma gamma low-energy theorem *)
Fpigg = echarge^2 Nc/(12 Pi^2 Fpi);
Print["Eq.(2)  F_pi-gamma-gamma = ", Fpigg, " GeV^-1"];"}

{"code":"(* Eq.(5): center-of-mass kinematics *)
sigmaPi[s_] := Sqrt[1 - 4 Mpi^2/s];          (* sigma^pi_s *)
as[s_] := (3 Mpi^2 - s)/2;                    (* a_s *)
bs[s_] := (s - Mpi^2)/2 * sigmaPi[s];         (* b_s *)
tof[s_, z_] := as[s] + bs[s] z;               (* t = a_s + b_s z *)
uof[s_, z_] := as[s] - bs[s] z;               (* u = a_s - b_s z *)

(* on-shell check: s + t + u = 3 Mpi^2 *)
Print["s+t+u check: ", Simplify[s + tof[s, z] + uof[s, z]], " = 3 Mpi^2 = ", 3 Mpi^2];

(* Eq.(7): P-wave projection f_1(s) = 3/4 Int_{-1}^1 dz (1-z^2) F.
   Verify against Eq.(6): F = sum_{odd l} f_l P_l'(z); for pure P-wave F=f1*P1'(z)=f1 *)
Pp[l_, z_] := D[LegendreP[l, x], x] /. x -> z;
Print["P_1'(z) = ", Pp[1, z]];
proj1 = 3/4 Integrate[(1 - z^2) (f1*Pp[1, z]), {z, -1, 1}];
Print["Eq.(7) projection of pure P-wave: ", Simplify[proj1], "  (should give f1)"];"}

{"code":"(* We need a pi-pi P-wave phase shift delta_1^1(s). Use a simple
   physically motivated model (Bethe-Salpeter/elastic rho) for demonstration. *)
Grho = 0.1491; (* GeV, rho width *)
qpi[s_] := Sqrt[s/4 - Mpi^2];
(* energy-dependent width and a standard rho phase model *)
GammaRho[s_] := Grho (s/Mrho^2) (qpi[s]/qpi[Mrho^2])^3;
delta11[s_] := ArcTan[Mrho GammaRho[s], Mrho^2 - s];  (* returns angle in (0,pi) *)

(* Eq.(9): pi-pi P-wave amplitude t_1^1(s) = (e^{2 i delta}-1)/(2 i sigma) *)
t11[s_] := (Exp[2 I delta11[s]] - 1)/(2 I sigmaPi[s]);

Print["delta11 at rho mass (deg): ", delta11[Mrho^2]*180/Pi];
Print["t11 at s=0.5 GeV^2: ", t11[0.5]];

(* Eq.(8): unitarity Im f1 = sigma (t11)^* f1  (Watson's theorem: phase of f1 = delta11).
   Check: if f1 = |f1| e^{i delta}, then Im(sigma t11^* f1) phase consistency *)
ftest = Abs[f1] Exp[I delta11[s]];
lhs = Im[ftest];
rhs = sigmaPi[s] Conjugate[t11[s]] ftest;
Print["Watson check at s=0.5, |f1|=1: Im f1 = ", 
  Im[Exp[I delta11[0.5]]], "  vs  sigma t11^* f1 = ", 
  N[sigmaPi[0.5] Conjugate[t11[0.5]] Exp[I delta11[0.5]]]];"}

{"code":"delta11[s_] := ArcTan[Mrho^2 - s, Mrho GammaRho[s]];  (* arg of (Mrho^2-s)+i Mrho Gamma *)
t11[s_] := (Exp[2 I delta11[s]] - 1)/(2 I sigmaPi[s]);
Print["delta11 at rho mass (deg): ", delta11[Mrho^2]*180/Pi];
Print["delta11 at s=0.9 GeV^2 (deg): ", delta11[0.9]*180/Pi];

(* Eq.(10): cross section sigma(s) for a given amplitude F(s,t,u) *)
crossSection[Famp_, s_] := 
  (s - 4 Mpi^2)^(3/2) (s - Mpi^2)/(1024 Pi Sqrt[s]) *
   NIntegrate[(1 - z^2) Abs[Famp[s, tof[s, z], uof[s, z]]]^2, {z, -1, 1}];

(* Constant (LET) amplitude F = F3pi as a trivial test *)
Fconst[s_, t_, u_] := F3pi;
Print["Eq.(10) cross section at s=0.5 GeV^2 (LET const amp): ",
   crossSection[Fconst, 0.5], " GeV^-2"];

(* Eq.(11): electromagnetic correction F -> F - 2 e^2 Fpi^2/t F3pi *)
emCorrection[Famp_, s_, t_, u_] := Famp[s, t, u] - 2 echarge^2 Fpi^2/t * F3pi;
Print["Eq.(11) em-corrected amp at s=0.5,z=0.3: ",
   emCorrection[Fconst, 0.5, tof[0.5, 0.3], uof[0.5, 0.3]]];"}

{"code":"sth = 4 Mpi^2;            (* two-pion threshold *)
Lambda = 1.8^2;          (* integration cutoff Lambda=1.8 GeV -> in s: (1.8)^2 *)

(* Eq.(20): Omnes function. For s below threshold (real, s<sth) integrand regular. *)
OmegaBelow[s_?NumericQ] := Exp[ (s/Pi) NIntegrate[ delta11[sp]/(sp (sp - s)),
     {sp, sth, Lambda}, Method -> "GlobalAdaptive"] ];

(* derivative dOmega/ds at s=0 : Omega(0)=1, Omega'(0)= (1/pi) Int delta/sp^2 *)
OmegaDot0 = (1/Pi) NIntegrate[ delta11[sp]/sp^2, {sp, sth, Lambda} ];
Print["Eq.(19) dOmega(0) = ", OmegaDot0, " GeV^-2"];

Print["Omega(0)   = ", OmegaBelow[0.0]];
Print["Omega(-1)  = ", OmegaBelow[-1.0]];

(* Modulus on the cut: |Omega(s)| = exp{ (s/pi) PV Int delta/(sp(sp-s)) } *)
OmegaMod[s_?NumericQ] := Exp[ (s/Pi) NIntegrate[ (delta11[sp]-delta11[s])/(sp (sp - s)),
     {sp, sth, Lambda}, Method -> "GlobalAdaptive"] 
     + (delta11[s]/Pi)*( Log[Abs[(Lambda - s)/(s-sth)]]/1 - Log[Lambda/sth] )*0
     ];
(* simpler robust modulus via PV using subtracted integrand *)
OmegaModulus[s_?NumericQ] := Module[{d = delta11[s]},
  Exp[ (s/Pi) ( NIntegrate[(delta11[sp] - d)/(sp (sp - s)), {sp, sth, Lambda}] 
       + d/s*Log[Abs[(Lambda - s)/(s - sth) ]] - d*Log[Lambda/sth]/s ) ] ];
Print["|Omega| at rho peak s=Mrho^2: ", OmegaModulus[Mrho^2]];"}

{"code":"(* Precompute |Omega(s')| on a grid over the cut for use in dispersive integrals *)
sGrid = Table[sth + (Lambda - sth) (k/60)^1.3, {k, 0, 60}];  (* denser near threshold *)
omAbsData = Table[{sp, OmegaModulus[sp]}, {sp, sGrid}];
OmAbs = Interpolation[omAbsData, InterpolationOrder -> 3];
Print["|Omega| interpolation built. Sample |Omega|(0.6)= ", OmAbs[0.6]];

(* Omega below threshold (real, regular) reuse OmegaBelow; build interpolation too *)
tGrid = Table[t, {t, -1.4, sth - 0.001, 0.05}];
omBelowData = Table[{t, OmegaBelow[t]}, {t, tGrid}];
OmBelow = Interpolation[omBelowData, InterpolationOrder -> 3];
Print["Omega(-0.3) = ", OmBelow[-0.3]];"}

{"code":"sGrid = Table[sth*1.0005 + (Lambda - sth*1.0005) (k/60)^1.3, {k, 0, 60}];
omAbsData = Table[{sp, OmegaModulus[sp]}, {sp, sGrid}];
OmAbs = Interpolation[omAbsData, InterpolationOrder -> 3];
Print["|Omega| grid built. |Omega|(0.6)= ", OmAbs[0.6], ",  |Omega|(Mrho^2)= ", OmAbs[Mrho^2]];"}

{"code":"(* Robust modulus: tell NIntegrate that s is a special interior point so it never samples exactly s *)
OmegaModulus[s_?NumericQ] := Module[{d = delta11[s]},
  Exp[ (s/Pi) ( NIntegrate[(delta11[sp] - d)/(sp (sp - s)), {sp, sth*1.0005, s, Lambda},
        Method -> "GlobalAdaptive"] 
       + d/s*Log[Abs[(Lambda - s)/(s - sth*1.0005)]] - d*Log[Lambda/(sth*1.0005)]/s ) ] ];
sGrid = Table[sth*1.0005 + (Lambda - sth*1.0005) (k/50)^1.3, {k, 1, 50}];
omAbsData = Table[{sp, OmegaModulus[sp]}, {sp, sGrid}];
OmAbs = Interpolation[omAbsData, InterpolationOrder -> 3];
Print["|Omega|(0.6)= ", OmAbs[0.6], ",  |Omega|(Mrho^2)= ", OmAbs[Mrho^2]];"}

{"code":"s0 = 0.6; d0 = delta11[s0];
test1 = NIntegrate[(delta11[sp] - d0)/(sp (sp - s0)), {sp, sth*1.0005, s0, Lambda}];
Print["subtracted PV integral = ", test1];
test2 = d0/s0*Log[Abs[(Lambda - s0)/(s0 - sth*1.0005)]] - d0*Log[Lambda/(sth*1.0005)]/s0;
Print["analytic log terms = ", test2];
Print["OmegaModulus[0.6] = ", Exp[(s0/Pi)(test1 + test2)]];"}

{"code":"Clear[OmegaModulus];
OmegaModulus[s_?NumericQ] := Module[{d = delta11[s], reg, pvpart, regpart},
  reg[sp_] := If[Abs[sp - s] < 1.*^-5,
     (delta11[s + 1.*^-4] - delta11[s - 1.*^-4])/(2.*^-4),
     (delta11[sp] - d)/(sp - s)];
  pvpart = NIntegrate[reg[sp], {sp, sth*1.0005, Lambda}] 
           + d*Log[Abs[(Lambda - s)/(s - sth*1.0005)]];   (* = PV Int delta/(sp-s) *)
  regpart = NIntegrate[delta11[sp]/sp, {sp, sth*1.0005, Lambda}];  (* Int delta/sp *)
  Exp[(1/Pi)(pvpart - regpart)]
];
Print["|Omega|(0.6)   = ", OmegaModulus[0.6]];
Print["|Omega|(Mrho^2)= ", OmegaModulus[Mrho^2]];
sGrid = Table[sth*1.0005 + (Lambda - sth*1.0005) (k/45)^1.3, {k, 1, 45}];
omAbsData = Table[{sp, OmegaModulus[sp]}, {sp, sGrid}];
OmAbs = Interpolation[omAbsData, InterpolationOrder -> 3];
Print["Interpolation built. peak near rho |Omega|= ", Max[omAbsData[[All, 2]]]];"}

{"code":"(* Robust |Omega| on the cut *)
Clear[OmegaModulus];
OmegaModulus[s_?NumericQ] := Module[{d = delta11[s], reg},
  reg[sp_] := If[Abs[sp - s] < 2.*^-5,
     (delta11[s + 1.*^-4] - delta11[s - 1.*^-4])/(2.*^-4),
     (delta11[sp] - d)/(sp - s)];
  Exp[(1/Pi)( NIntegrate[reg[sp], {sp, sth*1.0005, Lambda}]
       + d*Log[Abs[(Lambda - s)/(s - sth*1.0005)]]
       - NIntegrate[delta11[sp]/sp, {sp, sth*1.0005, Lambda}] )]
];
(* Build cut grid, ensure all numeric *)
sGrid = Table[sth*1.001 + (Lambda - sth*1.001) (k/40)^1.25, {k, 0, 40}];
