(* ln|Omega(s)| for s on the cut via subtracted trapezoid PV integral *)
lnOmegaCut[s_?NumericQ] := Module[{ds0 = delta11[s], integ},
  integ = MapThread[
    Function[{sp, dp}, If[Abs[sp - s] < 0.5 ds,
        (* near-singular: use local derivative of delta *)
        ((delta11[s + ds] - delta11[s - ds])/(2 ds)) ,
        (dp - ds0)/(sp - s)]], {sf, deltaArr}];
  (1/Pi)( Total[integ] ds + ds0*Log[Abs[(Lambda - s)/(s - sth)]]
          - Total[deltaArr/sf] ds )
];
