{"code":"(* Eq.(21) modulus on the cut for the basis (b0=1) *)
f1modBasis[s_]:=Module[{integ},
  integ=MapThread[Function[{sp,w,h},If[Abs[sp-s]<0.5 ds,0.,h w/(sp-s)]],{sf,wArr,hatArr}];
  hatOf[s,hatArr] Cos[delta11[s]] + omCutInterp[s](1+(s/Pi) Total[integ] ds)];

(* basis single-variable pieces *)
FsubB[x_]:=FsubFun[x,hatArr];                 (* subthreshold, real *)
(* complex F(s) on the cut for the basis: F=f1 - hatF, f1=|f1|e^{i delta} *)
FcutB[s_]:=Module[{m=f1modBasis[s],d=delta11[s],h=hatOf[s,hatArr]},
   (m Cos[d]-h)+I (m Sin[d])];

(* full amplitude F(s,t,u) for given subtraction constant C (scale C/3), with em corr *)
Famp[s_,z_,Cc_]:=Module[{t=as[s]+bs[s] z,u=as[s]-bs[s] z},
  (Cc/3)(FcutB[s]+FsubB[t]+FsubB[u]) - 2 echarge^2 Fpi^2/t F3pi];

(* Eq.(10) cross section *)
