sigmaCS[s_,Cc_]:=(s-4 Mpi^2)^(3/2)(s-Mpi^2)/(1024 Pi Sqrt[s])*
   (2/nzz) Total[Table[(1-z^2) Abs[Famp[s,z,Cc]]^2,{z,zz}]];

