  pref=(s-4 Mpi^2)^(3/2)(s-Mpi^2)/(1024 Pi Sqrt[s]);
  acc=Table[Module[{t=as[s]+bs[s] z,u=as[s]-bs[s] z},
        (1-z^2) Abs[(Cc/3)(Fc+FsubB[t]+FsubB[u])-2 echarge^2 Fpi^2/t F3pi]^2],{z,zz}];
  pref (2/nzz) Total[acc]];

